import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    
    // Các trạng thái cho thanh thời lượng
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    
    const audioRef = useRef(null);
    const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    // Hàm định dạng giây thành mm:ss (ví dụ: 90s -> 01:30)
    const formatTime = (time) => {
        if (isNaN(time)) return "00:00";
        const mins = Math.floor(time / 60);
        const secs = Math.floor(time % 60);
        return `${mins < 10 ? '0' : ''}${mins}:${secs < 10 ? '0' : ''}${secs}`;
    };

    // Khi nhạc đang chạy, cập nhật thanh tiến trình
    const onTimeUpdate = () => {
        setCurrentTime(audioRef.current.currentTime);
    };

    // Khi file nhạc đã tải xong thông tin (để lấy tổng thời gian)
    const onLoadedMetadata = () => {
        setDuration(audioRef.current.duration);
    };

    // Khi người dùng kéo thanh thời gian
    const handleSeek = (e) => {
        const seekTime = e.target.value;
        audioRef.current.currentTime = seekTime;
        setCurrentTime(seekTime);
    };

    const playSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    const nextSong = () => {
        const nextIndex = (currentIndex + 1) % songs.length;
        setCurrentIndex(nextIndex);
        setIsPlaying(true);
    };

    const prevSong = () => {
        const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
        setCurrentIndex(prevIndex);
        setIsPlaying(true);
    };

    const togglePlay = () => {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    return (
        <div style={{ padding: '20px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'Arial', paddingBottom: '150px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '40px', fontSize: '28px' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={{
                        display: 'flex', alignItems: 'center', padding: '15px 30px', border: '1px solid #eee', 
                        borderRadius: '15px', background: '#fff', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', justifyContent: 'space-between'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', flex: 1 }}>
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/80'} 
                                 style={{ width: '80px', height: '80px', marginRight: '25px', borderRadius: '10px', objectFit: 'cover' }} alt="cover"/>
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '20px' }}>{song.title}</div>
                                <div style={{ fontSize: '16px', color: '#888' }}>{song.artist}</div>
                            </div>
                        </div>
                        <button onClick={() => playSong(index)} style={{ padding: '12px 35px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '30px', cursor: 'pointer', fontWeight: 'bold' }}>
                            PLAY
                        </button>
                    </div>
                ))}
            </div>

            {/* THANH ĐIỀU KHIỂN NHẠC CÓ THANH THỜI LƯỢNG */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#181818', color: '#fff', padding: '15px 40px', 
                    display: 'flex', flexDirection: 'column', alignItems: 'center', zIndex: 1000,
                    boxShadow: '0 -5px 20px rgba(0,0,0,0.3)'
                }}>
                    
                    {/* HÀNG 1: Thông tin và Nút bấm */}
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%', marginBottom: '10px' }}>
                        {/* Trái: Thông tin */}
                        <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                            <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px', marginRight: '15px' }} alt="mini-cover" />
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '14px', whiteSpace: 'nowrap' }}>{currentSong.title}</div>
                                <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                            </div>
                        </div>

                        {/* Giữa: Nút điều khiển */}
                        <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
                            <button onClick={prevSong} style={btnIconStyle}>⏮</button>
                            <button onClick={togglePlay} style={btnMainPlayStyle}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                            <button onClick={nextSong} style={btnIconStyle}>⏭</button>
                        </div>

                        {/* Phải: Âm lượng (tạm để trống để cân đối) */}
                        <div style={{ width: '30%' }}></div>
                    </div>

                    {/* HÀNG 2: THANH THỜI LƯỢNG (SEEK BAR) */}
                    <div style={{ display: 'flex', alignItems: 'center', width: '100%', maxWidth: '700px', gap: '10px' }}>
                        <span style={{ fontSize: '12px', color: '#b3b3b3', minWidth: '35px' }}>{formatTime(currentTime)}</span>
                        
                        <input 
                            type="range" 
                            min="0" 
                            max={duration || 0} 
                            value={currentTime} 
                            onChange={handleSeek}
                            style={{ 
                                flex: 1, 
                                cursor: 'pointer',
                                accentColor: '#28a745', // Màu xanh cho thanh kéo
                                height: '4px'
                            }} 
                        />
                        
                        <span style={{ fontSize: '12px', color: '#b3b3b3', minWidth: '35px' }}>{formatTime(duration)}</span>
                    </div>

                    <audio 
                        ref={audioRef}
                        src={`http://localhost:5000${currentSong.songUrl}`} 
                        autoPlay 
                        onTimeUpdate={onTimeUpdate}
                        onLoadedMetadata={onLoadedMetadata}
                        onEnded={nextSong}
                    />
                </div>
            )}
        </div>
    );
};

const btnIconStyle = { background: 'none', border: 'none', color: '#fff', fontSize: '24px', cursor: 'pointer' };
const btnMainPlayStyle = {
    background: '#fff', border: 'none', color: '#000', width: '40px', height: '40px', 
    borderRadius: '50%', fontSize: '18px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center'
};

export default Home;
